/* ── Wipe (debug + privacy) ─────────────────────────────────────── */

export async function clearIdbStore(): Promise<void> {
  if (!isBrowser()) return;
  try {
    const db = await openDb();
    const stores = Array.from(db.objectStoreNames);
    await tx(stores, "readwrite", async (t) => {
      for (const name of stores) t.objectStore(name).clear();
    });
  } catch {
    /* ignore */
  }
}

